import type { IGomokuPiece, IShapeScoreMap } from '@algorithm.ts/gomoku'
import { GomokuSolution } from '@algorithm.ts/gomoku'
import { GomokuPlayerType } from '@kyokuya/react-game-gomoku-core'
import type { IPlayer } from '../../types'
import type { IBasePlayerProps } from './BasePlayer'
import { BasePlayer } from './BasePlayer'

export interface ICleverComputerPlayerProps extends IBasePlayerProps {
  MAX_ADJACENT?: number
  MAX_DISTANCE_OF_NEIGHBOR?: number
  scoreMap?: IShapeScoreMap
}

export class CleverComputerPlayer extends BasePlayer implements IPlayer {
  public readonly type = GomokuPlayerType.COMPUTER
  protected readonly solution: GomokuSolution

  constructor(props: ICleverComputerPlayerProps) {
    super(props)
    this.solution = new GomokuSolution({
      MAX_ROW: props.MAX_ROW,
      MAX_COL: props.MAX_COL,
      MAX_ADJACENT: props.MAX_ADJACENT,
      MAX_DISTANCE_OF_NEIGHBOR: props.MAX_DISTANCE_OF_NEIGHBOR,
      scoreMap: props.scoreMap,
    })
  }

  public override init(pieces: ReadonlyArray<IGomokuPiece>): void {
    this.solution.init(pieces)
  }

  public override move(): [r: number, c: number] {
    return this.solution.minimaxSearch(this.playerId)
  }

  public override forward(r: number, c: number, p: number): void {
    this.solution.forward(r, c, p)
  }

  public override rollback(r: number, c: number): void {
    this.solution.revert(r, c)
  }
}
