import type { IGomokuPiece } from '@algorithm.ts/gomoku'
import type { GomokuPlayerType } from '@kyokuya/react-game-gomoku-core'
import type { IPlayer, IPlayerInfo, IPlayerPreferenceSettings } from '../../types'
import { DOUBLE_PI } from '../constant'

export const defaultPreferenceSettings: Record<number, IPlayerPreferenceSettings> = {
  0: {
    pieceStrokeStyle: '#000',
    pieceFillStyle: '#111',
  },
  1: {
    pieceStrokeStyle: '#fff',
    pieceFillStyle: '#eee',
  },
}

export interface IBasePlayerProps {
  readonly name: string
  readonly playerId: number
  readonly MAX_ROW: number
  readonly MAX_COL: number
  readonly preferenceSettings: IPlayerPreferenceSettings
}

export abstract class BasePlayer implements IPlayer {
  public abstract readonly type: GomokuPlayerType
  public readonly name: string
  public readonly playerId: number
  protected readonly MAX_ROW: number
  protected readonly MAX_COL: number
  protected preferenceSettings: IPlayerPreferenceSettings

  constructor(props: IBasePlayerProps) {
    this.name = props.name
    this.playerId = props.playerId
    this.MAX_ROW = props.MAX_ROW
    this.MAX_COL = props.MAX_COL
    this.preferenceSettings = props.preferenceSettings
  }

  public async reset(props: {
    name?: string
    playerId?: number
    MAX_ROW?: number
    MAX_COL?: number
  }): Promise<void> {
    if (props.name != null) {
      ;(this.name as string) = props.name
    }
    if (props.playerId != null) {
      ;(this.playerId as number) = props.playerId
    }
    if (props.MAX_ROW != null) {
      ;(this.MAX_ROW as number) = props.MAX_ROW
    }
    if (props.MAX_COL != null) {
      ;(this.MAX_COL as number) = props.MAX_COL
    }
  }

  public abstract init(pieces: ReadonlyArray<IGomokuPiece>): void
  public abstract move(): [r: number, c: number]
  public abstract forward(r: number, c: number, p: number): void
  public abstract rollback(r: number, c: number): void

  public onUserInputChange(r: number, c: number): void {}

  public draw(context: CanvasRenderingContext2D, x: number, y: number, radius: number): void {
    const { pieceStrokeStyle, pieceFillStyle } = this.preferenceSettings
    // eslint-disable-next-line no-param-reassign
    context.strokeStyle = pieceStrokeStyle
    // eslint-disable-next-line no-param-reassign
    context.fillStyle = pieceFillStyle
    context.beginPath()
    context.arc(x, y, radius, 0, DOUBLE_PI, false)
    context.closePath()
    context.stroke()
    context.fill()
  }

  public toJSON(): IPlayerInfo {
    const { type, name } = this
    return { type, name }
  }
}
