import { useReactiveRef } from '@guanghechen/react-hooks'
import { composeMiddlewares } from '@kyokuya/react-hooks'
import PropTypes from 'prop-types'
import React from 'react'
import { GomokuGameContextType } from './context'
import type { IGomokuGameContext, IGomokuGameContextMiddleware } from './context'
import { builtinReducer } from './reducer'
import type { IGomokuGameState } from './state'
import { initGomokuGameState } from './state'

export interface IGomokuGameContextProviderProps {
  /**
   * Initial context data.
   */
  initialState?: Partial<IGomokuGameState>
  /**
   * Descendant elements.
   */
  children: React.ReactNode
  /**
   * Context middlewares.
   */
  middlewares?: IGomokuGameContextMiddleware[]
}

const GomokuGameContextProviderInner: React.FC = props => {
  const stateRef = useReactiveRef(React.useContext(GomokuGameContextType).state)
  const { players, gameTick } = stateRef.current

  React.useEffect(() => {
    for (const player of players) {
      player.init(stateRef.current.pieces)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [players, gameTick])

  return <React.Fragment>{props.children}</React.Fragment>
}

export const GomokuGameContextProvider: React.FC<IGomokuGameContextProviderProps> = props => {
  const { children, initialState, middlewares } = props
  const reducer = React.useMemo(
    () => composeMiddlewares(...(middlewares ?? []), builtinReducer)(state => state),
    [middlewares],
  )
  const [state, dispatch] = React.useReducer(reducer, initialState, initGomokuGameState)
  const context: IGomokuGameContext = React.useMemo(() => ({ state, dispatch }), [state, dispatch])
  return (
    <GomokuGameContextType.Provider value={context}>
      <GomokuGameContextProviderInner>{children}</GomokuGameContextProviderInner>{' '}
    </GomokuGameContextType.Provider>
  )
}

GomokuGameContextProvider.propTypes = {
  initialState: PropTypes.any,
  children: PropTypes.node.isRequired,
}

GomokuGameContextProvider.displayName = 'GomokuGameContextProvider'
