import { css, cx } from '@emotion/css'
import type { SelectChangeEvent } from '@mui/material'
import { MenuItem, Select } from '@mui/material'
import React from 'react'

export interface IGameSettingsGomokuSizeProps {
  size: number
  disabled: boolean
  className?: string
  onSizeChange?(size: number): void
}

export const GameSettingsGomokuSize: React.FC<IGameSettingsGomokuSizeProps> = props => {
  const { size, disabled, onSizeChange } = props

  const handleSizeChange = React.useCallback(
    (e: SelectChangeEvent<number>): void => {
      const value = Number(e.target.value)
      onSizeChange?.(value)
    },
    [onSizeChange],
  )

  const classes = useStyles()
  return (
    <div className={cx(classes.container, props.className)}>
      <span className={classes.label}>Size:</span>
      <Select
        className={classes.input}
        variant="standard"
        value={size}
        disabled={disabled}
        onChange={handleSizeChange}
      >
        <MenuItem value={5}>5</MenuItem>
        <MenuItem value={7}>7</MenuItem>
        <MenuItem value={9}>9</MenuItem>
        <MenuItem value={11}>11</MenuItem>
        <MenuItem value={13}>13</MenuItem>
        <MenuItem value={15}>15</MenuItem>
        <MenuItem value={17}>17</MenuItem>
        <MenuItem value={19}>19</MenuItem>
        <MenuItem value={21}>21</MenuItem>
        <MenuItem value={23}>23</MenuItem>
        <MenuItem value={25}>25</MenuItem>
      </Select>
    </div>
  )
}

// eslint-disable-next-line @typescript-eslint/explicit-function-return-type
const useStyles = () => ({
  container: css`
    display: flex;
    align-items: center;
  `,
  label: css`
  `,
  input: css`
    && {
      margin-left: 1rem;
    }
  `,
})
